const errors = [];
for (const field of ['run_id', 'task_id', 'goal', 'criteria', 'iteration', 'instruction', 'status']) {
  if ($json[field] === undefined || $json[field] === null || $json[field] === '') {
    errors.push(`${field} is required`);
  }
}
if (!Array.isArray($json.criteria) || $json.criteria.length === 0) {
  errors.push('criteria must contain at least one item');
}
return [{ json: { ...$json, validation_errors: errors } }];

const input = $json;

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const requestedMode =
  typeof context.provider_mode === 'string' && context.provider_mode.trim()
    ? context.provider_mode.trim()
    : typeof context.agent_mode === 'string' && context.agent_mode.trim()
      ? context.agent_mode.trim()
      : typeof input.provider_mode === 'string' && input.provider_mode.trim()
        ? input.provider_mode.trim()
        : typeof input.agent_mode === 'string' && input.agent_mode.trim()
          ? input.agent_mode.trim()
          : 'mock';

const supportedModes = new Set(['mock', 'dry-run', 'real-readonly']);
const resolvedMode = supportedModes.has(requestedMode)
  ? requestedMode
  : 'mock';

const modeWarnings = supportedModes.has(requestedMode)
  ? []
  : ['unknown provider mode fallback to mock'];

return [
  {
    json: {
      ...input,
      context: {
        ...context,
        agent_mode: resolvedMode,
        provider_mode: resolvedMode,
      },
      prompt_reference: 'src/prompts/subagent_prompt.md',
      prompt_contract: {
        output: 'result.schema.json',
        format: 'json_only',
      },
      agent_mode: resolvedMode,
      provider_mode: resolvedMode,
      requested_provider_mode: requestedMode,
      mode_warnings: modeWarnings,
    },
  },
];

if (($json.validation_errors || []).length > 0) {
  return [{
    json: {
      run_id: $json.run_id || 'unknown',
      task_id: $json.task_id || 'unknown',
      status: 'failed',
      summary: 'Task validation failed before execution.',
      artifacts: [],
      known_issues: $json.validation_errors,
      evidence: ($json.criteria || ['task payload']).map((criterion) => ({
        criterion,
        status: 'fail',
        detail: 'Executor could not run because the task payload was invalid.'
      })),
      next_action_suggestion: 'Fix the task payload and retry.',
      error: {
        code: 'TASK_VALIDATION_FAILED',
        message: $json.validation_errors.join('; ')
      }
    }
  }];
}

const evidence = ($json.criteria || []).map((criterion, index) => ({
  criterion,
  status: index < 2 ? 'pass' : 'fail',
  detail: index < 2
    ? `Mock executor produced evidence for criterion ${index + 1}.`
    : `Mock executor intentionally leaves criterion ${index + 1} unresolved.`
}));

return [{
  json: {
    run_id: $json.run_id,
    task_id: $json.task_id,
    status: evidence.every((item) => item.status === 'pass') ? 'completed' : 'partial',
    summary: 'Mock executor completed one bounded task iteration.',
    artifacts: ['docs/WORKFLOW_DESIGN.md'],
    known_issues: evidence.filter((item) => item.status !== 'pass').map((item) => item.detail),
    evidence,
    next_action_suggestion: 'Run Criteria Checker to assess whether another iteration is required.',
    error: null
  }
}];

const input = $json || {};
const agentResult =
  input.agent_result && typeof input.agent_result === 'object'
    ? input.agent_result
    : {};

const artifacts = Array.isArray(agentResult.artifacts)
  ? agentResult.artifacts
  : [];

const knownIssues = Array.isArray(agentResult.known_issues)
  ? agentResult.known_issues
  : [];

const criteria = Array.isArray(input.criteria)
  ? input.criteria
  : [];

return [
  {
    json: {
      ...input,
      execution_log: {
        logged_at: new Date().toISOString(),
        summary: agentResult.summary || 'Agent execution completed.',
        artifact_count: artifacts.length,
        issue_count: knownIssues.length,
        criteria_count: criteria.length,
        provider_mode:
          agentResult.provider && agentResult.provider.mode
            ? agentResult.provider.mode
            : input.provider_mode || input.agent_mode || 'mock',
      },
    },
  },
];

const input = $json || {};

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const criteria = Array.isArray(input.criteria)
  ? input.criteria
  : [];

const runId =
  input.run_id ||
  `gd_${Date.now()}`;

const taskId =
  input.task_id ||
  `task_${Date.now()}`;

const riskLevel =
  input.risk_level ||
  context.risk_level ||
  'low';

const evidence = criteria.map((criterion) => ({
  criterion,
  status: 'unknown',
  detail: 'Dry-run generated a plan but did not execute real work.',
}));

const intendedActions = [
  'Review the goal and acceptance criteria.',
  'Generate a bounded execution plan.',
  'Identify required artifacts and expected evidence.',
  'Request human approval before any real provider execution.',
];

return [
  {
    json: {
      ...input,

      run_id: runId,
      task_id: taskId,
      status: 'needs_review',

      summary: 'Dry-run plan generated. No real action was executed.',
      artifacts: [],
      known_issues: [],
      evidence,

      dry_run_plan: {
        goal: input.goal || '',
        intended_actions: intendedActions,
        risk_summary: `Dry-run only. No real action was executed. Current risk level: ${riskLevel}.`,
        requires_human_approval_before_real_run: true,
      },

      provider: {
        mode: 'dry-run',
        name: 'dry-run-provider',
        model: null,
        request_id: null,
        latency_ms: 0,
      },

      safety: {
        risk_level: riskLevel,
        requires_human_approval: true,
        approved: false,
        blocked_reason: 'dry-run mode does not execute real actions',
      },
    },
  },
];

const input = $json || {};

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const criteria = Array.isArray(input.criteria)
  ? input.criteria
  : [];

const runId =
  input.run_id ||
  `gd_${Date.now()}`;

const taskId =
  input.task_id ||
  `task_${Date.now()}`;

const riskLevel =
  input.risk_level ||
  context.risk_level ||
  'low';

const evidence = criteria.map((criterion) => ({
  criterion,
  status: 'unknown',
  detail: 'Real-readonly stub generated analysis but did not execute real work.',
}));

const intendedActions = [
  'Review the goal and acceptance criteria.',
  'Generate a read-only implementation plan.',
  'Identify expected evidence without executing changes.',
  'Request human approval before any real execution mode.',
];

return [
  {
    json: {
      ...input,

      run_id: runId,
      task_id: taskId,
      status: 'needs_review',

      summary: 'Real-readonly provider stub generated a review plan. No real action was executed.',
      artifacts: [],
      known_issues: [],
      evidence,
      intended_actions: intendedActions,
      risk_summary: `Real-readonly stub only. No real action was executed. Current risk level: ${riskLevel}.`,

      provider: {
        mode: 'real-readonly',
        name: 'real-readonly-stub',
        model: null,
        request_id: null,
        latency_ms: 0,
      },

      safety: {
        risk_level: riskLevel,
        requires_human_approval: true,
        approved: false,
        blocked_reason: 'real-readonly mode does not execute real actions',
      },
    },
  },
];

const adapterOutput = $json || {};

let taskInput = {};
try {
  taskInput = $('Prompt Builder').item.json || {};
} catch (error) {
  taskInput = {};
}

const context =
  taskInput.context && typeof taskInput.context === 'object'
    ? taskInput.context
    : adapterOutput.context && typeof adapterOutput.context === 'object'
      ? adapterOutput.context
      : {};

const runId =
  taskInput.run_id ||
  adapterOutput.run_id ||
  'gd_' + Date.now();

const taskId =
  taskInput.task_id ||
  adapterOutput.task_id ||
  'task_' + Date.now();

const goal =
  typeof taskInput.goal === 'string'
    ? taskInput.goal
    : typeof adapterOutput.goal === 'string'
      ? adapterOutput.goal
      : '';

const criteria = Array.isArray(taskInput.criteria)
  ? taskInput.criteria
  : Array.isArray(adapterOutput.criteria)
    ? adapterOutput.criteria
    : [];

const iteration =
  Number.isInteger(taskInput.iteration)
    ? taskInput.iteration
    : Number.isInteger(adapterOutput.iteration)
      ? adapterOutput.iteration
      : 1;

const artifacts = Array.isArray(adapterOutput.artifacts)
  ? adapterOutput.artifacts
  : [];

const knownIssues = Array.isArray(adapterOutput.known_issues)
  ? adapterOutput.known_issues
  : [];

const evidence = Array.isArray(adapterOutput.evidence)
  ? adapterOutput.evidence
  : [];

const resolvedMode =
  (adapterOutput.provider && adapterOutput.provider.mode) ||
  taskInput.provider_mode ||
  taskInput.agent_mode ||
  'mock';

const provider =
  adapterOutput.provider && typeof adapterOutput.provider === 'object'
    ? adapterOutput.provider
    : {
        mode: resolvedMode,
        name: resolvedMode === 'mock' ? 'mock-agent-adapter' : 'unknown-provider',
        model: null,
        request_id: null,
        latency_ms: 0,
      };

const riskLevel =
  adapterOutput.safety && adapterOutput.safety.risk_level
    ? adapterOutput.safety.risk_level
    : taskInput.risk_level || context.risk_level || 'low';

const safety =
  adapterOutput.safety && typeof adapterOutput.safety === 'object'
    ? adapterOutput.safety
    : {
        risk_level: riskLevel,
        requires_human_approval: resolvedMode !== 'mock',
        approved: resolvedMode === 'mock' ? true : Boolean(taskInput.human_approved),
        blocked_reason: resolvedMode === 'mock' ? null : 'provider mode requires explicit approval before real execution',
      };

const dryRunPlan =
  adapterOutput.dry_run_plan && typeof adapterOutput.dry_run_plan === 'object'
    ? adapterOutput.dry_run_plan
    : null;

const intendedActions = Array.isArray(adapterOutput.intended_actions)
  ? adapterOutput.intended_actions
  : null;

const riskSummary =
  typeof adapterOutput.risk_summary === 'string' && adapterOutput.risk_summary.trim()
    ? adapterOutput.risk_summary
    : null;

const modeWarnings = Array.isArray(adapterOutput.mode_warnings)
  ? adapterOutput.mode_warnings
  : Array.isArray(taskInput.mode_warnings)
    ? taskInput.mode_warnings
    : [];

return [
  {
    json: {
      ...taskInput,
      ...adapterOutput,
      run_id: runId,
      task_id: taskId,
      goal,
      criteria,
      context,
      iteration,
      agent_result: {
        run_id: runId,
        task_id: taskId,
        status: adapterOutput.status || 'failed',
        summary: adapterOutput.summary || 'Agent execution returned no summary.',
        artifacts,
        known_issues: knownIssues,
        evidence,
        provider,
        safety,
        ...(dryRunPlan ? { dry_run_plan: dryRunPlan } : {}),
        ...(intendedActions ? { intended_actions: intendedActions } : {}),
        ...(riskSummary ? { risk_summary: riskSummary } : {}),
        ...(modeWarnings.length > 0 ? { mode_warnings: modeWarnings } : {}),
      },
    },
  },
];

const input = $json || {};
const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const criteria = Array.isArray(input.criteria) ? input.criteria : [];
const riskLevel = input.risk_level || context.risk_level || 'low';
const humanApproved = Boolean(input.human_approved || context.human_approved);
const goalText = typeof input.goal === 'string' ? input.goal : '';
const criteriaText = criteria.join('\n');
const combinedText = (goalText + '\n' + criteriaText).toLowerCase();

const writeIntentPatterns = [
  /write\s+file/,
  /create\s+file/,
  /modify\s+file/,
  /delete\s+file/,
  /run\s+(a\s+)?shell/,
  /execute\s+(a\s+)?command/,
  /terminal\s+command/,
  /git\s+(commit|push|merge|reset|checkout)/,
  /modify\s+git/,
  /deploy\s+production/,
  /external\s+write/,
];

const blockedReasons = [];
if (String(riskLevel).toLowerCase() === 'high' && !humanApproved) {
  blockedReasons.push('high_risk_requires_human_approval');
}
if (writeIntentPatterns.some((pattern) => pattern.test(combinedText))) {
  blockedReasons.push('write_or_execution_intent_detected');
}

const endpoint =
  context.openai_compatible_base_url ||
  context.provider_endpoint ||
  input.openai_compatible_base_url ||
  input.provider_endpoint ||
  '';

const model =
  context.openai_compatible_model ||
  context.provider_model ||
  input.openai_compatible_model ||
  input.provider_model ||
  '{{ $env.OPENAI_COMPATIBLE_MODEL }}';

const credentialName =
  context.provider_credential_name ||
  input.provider_credential_name ||
  'goald-openai-compatible-readonly';

const credentialReady =
  context.provider_credential_ready === true ||
  input.provider_credential_ready === true;

const providerConfig = {
  interface: 'openai-compatible',
  mode: 'real-readonly',
  endpoint_env: 'OPENAI_COMPATIBLE_BASE_URL',
  model_env: 'OPENAI_COMPATIBLE_MODEL',
  endpoint_placeholder: endpoint || '{{ $env.OPENAI_COMPATIBLE_BASE_URL }}',
  endpoint_configured: Boolean(endpoint),
  credential_name: credentialName,
  credential_reference_only: true,
  credential_ready: credentialReady,
  model,
  timeout_ms: Number(context.provider_timeout_ms || input.provider_timeout_ms || 30000),
};

return [
  {
    json: {
      ...input,
      provider_execution: 'provider',
      provider_config: providerConfig,
      provider_safety_check: {
        read_only: true,
        blocked: blockedReasons.length > 0,
        blocked_reasons: blockedReasons,
      },
    },
  },
];

const input = $json || {};
const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const criteria = Array.isArray(input.criteria) ? input.criteria : [];
const providerConfig =
  input.provider_config && typeof input.provider_config === 'object'
    ? input.provider_config
    : {};
const safetyCheck =
  input.provider_safety_check && typeof input.provider_safety_check === 'object'
    ? input.provider_safety_check
    : { blocked: true, blocked_reasons: ['provider_safety_check_missing'] };

const baseProvider = {
  mode: 'real-readonly',
  name: 'openai-compatible-readonly',
  model: providerConfig.model || null,
  request_id: null,
  latency_ms: 0,
};

const baseSafety = {
  risk_level: input.risk_level || context.risk_level || 'low',
  requires_human_approval: true,
  approved: false,
  blocked_reason: null,
};

function fallback(reason, summary, status = 'needs_review') {
  return [{
    json: {
      ...input,
      status,
      summary,
      artifacts: [],
      known_issues: [reason],
      evidence: criteria.map((criterion) => ({
        criterion,
        status: 'unknown',
        detail: 'OpenAI-compatible real-readonly provider path did not execute because ' + reason + '.',
      })),
      intended_actions: [],
      risk_summary: 'Provider path stopped safely before any real action. No file write, shell execution, Git modification, or external write action occurred.',
      provider: baseProvider,
      safety: {
        ...baseSafety,
        blocked_reason: reason,
      },
      provider_error: {
        code: reason,
        message: summary,
      },
    }
  }];
}

if (safetyCheck.blocked) {
  return fallback(
    'safety_check_failed',
    'Real-readonly provider call blocked by safety check: ' + (safetyCheck.blocked_reasons || []).join(', '),
    'needs_review'
  );
}

if (!providerConfig.endpoint_configured) {
  return fallback(
    'provider_endpoint_missing',
    'Real-readonly provider endpoint is not configured.',
    'needs_review'
  );
}

if (!providerConfig.credential_ready) {
  return fallback(
    'provider_credential_missing',
    'Real-readonly provider credential is missing or has not been confirmed in n8n.',
    'needs_review'
  );
}

const providerRequest = {
  model: providerConfig.model,
  messages: [
    {
      role: 'system',
      content: 'You are a read-only planning and evidence generation adapter. Do not execute commands, write files, modify Git, call external write APIs, or claim that work was executed. Return JSON only.',
    },
    {
      role: 'user',
      content: {
        mode: 'real-readonly',
        goal: input.goal || '',
        criteria,
        iteration: input.iteration || 1,
        constraints: [
          'Do not execute commands.',
          'Do not write files.',
          'Do not modify Git.',
          'Do not call external write APIs.',
          'Return structured JSON only.',
        ],
        expected_output: {
          summary: 'string',
          intended_actions: ['string'],
          evidence: [
            {
              criterion: 'string',
              status: 'pass | fail | unknown',
              detail: 'string',
            },
          ],
          risk_summary: 'string',
        },
      },
    },
  ],
  temperature: 0.2,
  response_format: {
    type: 'json_object',
  },
};

return [{
  json: {
    ...input,
    provider_request: providerRequest,
    provider_call_status: 'prepared_not_sent',
    provider_response_raw: null,
    provider_error: {
      code: 'provider_call_disabled_in_repo_template',
      message: 'The OpenAI-compatible request was prepared but not sent by the repository workflow template.',
    },
  }
}];

const input = $json || {};
const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};
const criteria = Array.isArray(input.criteria) ? input.criteria : [];
const providerConfig =
  input.provider_config && typeof input.provider_config === 'object'
    ? input.provider_config
    : {};

const provider =
  input.provider && typeof input.provider === 'object'
    ? input.provider
    : {
        mode: 'real-readonly',
        name: 'openai-compatible-readonly',
        model: providerConfig.model || null,
        request_id: null,
        latency_ms: 0,
      };

const baseSafety = {
  risk_level: input.risk_level || context.risk_level || 'low',
  requires_human_approval: true,
  approved: false,
  blocked_reason: null,
};

function normalizeEvidence(rawEvidence) {
  if (!Array.isArray(rawEvidence)) {
    return criteria.map((criterion) => ({
      criterion,
      status: 'unknown',
      detail: 'Provider did not return evidence for this criterion.',
    }));
  }

  const allowed = new Set(['pass', 'fail', 'unknown']);
  return rawEvidence.map((item, index) => {
    const status = allowed.has(item && item.status) ? item.status : 'unknown';
    return {
      criterion: item && item.criterion ? item.criterion : criteria[index] || 'criterion_' + (index + 1),
      status,
      detail: item && item.detail ? item.detail : 'Provider evidence detail was missing.',
    };
  });
}

function safeResult(reason, summary, status = 'needs_review') {
  return [{
    json: {
      ...input,
      status,
      summary,
      artifacts: [],
      known_issues: [reason],
      evidence: normalizeEvidence(input.evidence),
      intended_actions: Array.isArray(input.intended_actions) ? input.intended_actions : [],
      risk_summary: input.risk_summary || 'Provider path stopped safely before execution.',
      provider,
      safety: {
        ...baseSafety,
        ...(input.safety && typeof input.safety === 'object' ? input.safety : {}),
        blocked_reason: reason,
      },
    }
  }];
}

if (input.provider_error && input.provider_error.code) {
  const code = input.provider_error.code;
  return safeResult(code, input.summary || input.provider_error.message || 'Provider path returned a safe fallback.', input.status || 'needs_review');
}

let content = input.provider_response_content || input.provider_response_raw || null;
if (typeof content === 'string') {
  try {
    content = JSON.parse(content);
  } catch (error) {
    return safeResult('provider_invalid_json', 'Provider returned invalid JSON.', 'failed');
  }
}

if (!content || typeof content !== 'object') {
  return safeResult('provider_response_missing', 'Provider response was missing.', 'failed');
}

const summary =
  typeof content.summary === 'string' && content.summary.trim()
    ? content.summary
    : 'Provider returned no summary.';
const intendedActions = Array.isArray(content.intended_actions)
  ? content.intended_actions
  : [];
const evidence = normalizeEvidence(content.evidence);
const riskSummary =
  typeof content.risk_summary === 'string' && content.risk_summary.trim()
    ? content.risk_summary
    : 'Risk summary was not provided by the provider.';

return [{
  json: {
    ...input,
    status: 'needs_review',
    summary,
    artifacts: [],
    known_issues: [],
    evidence,
    intended_actions: intendedActions,
    risk_summary: riskSummary,
    provider,
    safety: {
      ...baseSafety,
      ...(input.safety && typeof input.safety === 'object' ? input.safety : {}),
      requires_human_approval: true,
      approved: false,
      blocked_reason: null,
    },
  }
}];
